#!/bin/bash
# Download all artwork images from tiffanychen.site CDN (with auth hashes)
set -e

download() {
  local dir="$1"
  local filename="$2"
  local url="$3"
  local dest="public/images/${dir}/${filename}"

  curl -sL -o "$dest" "$url"
  if [ -s "$dest" ] && ! file "$dest" | grep -q "JSON"; then
    echo "OK: $dest ($(wc -c < "$dest" | tr -d ' ') bytes)"
  else
    echo "FAIL: $dest"
    rm -f "$dest"
  fi
}

